  2	
  3	import { DRAWER_FORM_ID } from '@catalog/templatescatalog/utils/consts';
  4	import FolderSelect from '@kubevirt-utils/components/FolderSelect/FolderSelect';
  5	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
  6	import { validateVMName } from '@kubevirt-utils/components/VMNameValidationHelperText/utils/utils';
