  8	import {
  9	  RUNSTRATEGY_ALWAYS,
 10	  RUNSTRATEGY_RERUNONFAILURE,
 11	} from '@kubevirt-utils/constants/constants';
 12	import { TREE_VIEW_FOLDERS } from '@kubevirt-utils/hooks/useFeatures/constants';
 13	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
 14	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 15	import { RHELAutomaticSubscriptionData } from '@kubevirt-utils/hooks/useRHELAutomaticSubscription/utils/types';
 16	import {
 17	  Alert,
 18	  AlertVariant,
 19	  Button,
 20	  ButtonVariant,
 21	  Checkbox,
 22	  DescriptionList,
 23	  FormGroup,
 24	  Split,
 25	  SplitItem,
 26	  Stack,
 27	  StackItem,
 28	  TextInput,
 29	  Tooltip,
 30	} from '@patternfly/react-core';
 31	
 32	import useCreateDrawerForm from './hooks/useCreateDrawerForm';
 33	import { useDrawerContext } from './hooks/useDrawerContext';
 34	import AuthorizedSSHKey from './AuthorizedSSHKey';
 35	
 36	type TemplatesCatalogDrawerCreateFormProps = {
 37	  authorizedSSHKey: string;
 38	  namespace: string;
 39	  onCancel: () => void;
 40	  subscriptionData: RHELAutomaticSubscriptionData;
 41	};
 42	
 43	export const TemplatesCatalogDrawerCreateForm: FC<TemplatesCatalogDrawerCreateFormProps> = memo(
 44	  ({ authorizedSSHKey, namespace, onCancel, subscriptionData }) => {
 45	    const { t } = useKubevirtTranslation();
 46	
 47	    const { isBootSourceAvailable, templateLoadingError } = useDrawerContext();
 48	
 49	    const { featureEnabled: treeViewFoldersEnabled } = useFeatures(TREE_VIEW_FOLDERS);
 50	
 51	    const {
 52	      createError,
 53	      folder,
 54	      isCustomizeDisabled,
 55	      isCustomizeLoading,
 56	      isQuickCreateDisabled,
 57	      isQuickCreateLoading,
 58	      nameField,
 59	      onChangeFolder,
 60	      onChangeStartVM,
 61	      onCustomize,
 62	      onQuickCreate,
 63	      onVMNameChange,
 64	      runStrategy,
 65	      startVM,
 66	    } = useCreateDrawerForm(namespace, subscriptionData, authorizedSSHKey);
 67	
 68	    const vmNameValidated = validateVMName(nameField);
 69	
 70	    const error = templateLoadingError || createError;
 71	    return (
 72	      <form className="template-catalog-drawer-form" id="quick-create-form">
 73	        <Stack hasGutter>
 74	          <>
 75	            <StackItem>
 76	              <Split hasGutter>
 77	                <SplitItem className="template-catalog-drawer-form-name" isFilled>
 78	                  <FormGroup fieldId="vm-name-field" isRequired label={t('VirtualMachine name')}>
 79	                    <TextInput
 80	                      aria-label="virtualmachine name"
 81	                      data-test-id="template-catalog-vm-name-input"
 82	                      isDisabled={Boolean(templateLoadingError)}
 83	                      isRequired
 84	                      name="vmname"
 85	                      onChange={(_, value: string) => onVMNameChange(value)}
 86	                      type="text"
 87	                      validated={vmNameValidated}
 88	                      value={nameField}
 89	                    />
 90	                  </FormGroup>
 91	                  <VMNameValidationHelperText vmName={nameField} />
 92	                </SplitItem>
 93	                {treeViewFoldersEnabled && (
 94	                  <SplitItem>
 95	                    <FormGroup fieldId="vm-folder-field" isRequired label={t('Folder')}>
 96	                      <FolderSelect
 97	                        setSelectedFolder={(newFolder) => {
 98	                          onChangeFolder(newFolder);
 99	                        }}
100	                        namespace={namespace}
101	                        selectedFolder={folder}
102	                      />
103	                    </FormGroup>
104	                  </SplitItem>
105	                )}
106	                <SplitItem>
107	                  <DescriptionList className="pf-v6-c-description-list">
108	                    <VirtualMachineDescriptionItem
109	                      descriptionData={namespace}
110	                      descriptionHeader={t('Project')}
111	                    />
112	                  </DescriptionList>
113	                </SplitItem>
114	                <AuthorizedSSHKey authorizedSSHKey={authorizedSSHKey} namespace={namespace} />
115	              </Split>
116	            </StackItem>
117	            <StackItem />
118	            <StackItem>
119	              <Checkbox
120	                isChecked={
121	                  startVM ||
122	                  runStrategy === RUNSTRATEGY_ALWAYS ||
123	                  runStrategy === RUNSTRATEGY_RERUNONFAILURE
124	                }
125	                label={
126	                  runStrategy
127	                    ? t('Start this VirtualMachine after creation ({{runStrategy}})', {
128	                        runStrategy,
129	                      })
130	                    : t('Start this VirtualMachine after creation')
131	                }
132	                id="start-after-create-checkbox"
133	                onChange={(_, checked: boolean) => onChangeStartVM(checked)}
134	              />
135	            </StackItem>
136	          </>
137	          <StackItem />
138	          {error && (
139	            <StackItem>
140	              <Alert isInline title={t('Quick create error')} variant={AlertVariant.danger}>
141	                <Stack hasGutter>
142	                  <StackItem>{error.message}</StackItem>
143	                  {error?.href && (
144	                    <StackItem>
145	                      <a href={error.href} rel="noreferrer" target="_blank">
146	                        {error.href}
147	                      </a>
148	                    </StackItem>
149	                  )}
150	                </Stack>
151	              </Alert>
152	            </StackItem>
153	          )}
154	
155	          <StackItem>
156	            <Split hasGutter>
157	              <SplitItem>
158	                <Tooltip
159	                  content={
160	                    isBootSourceAvailable
161	                      ? t(
162	                          'To enable Quick create button, fill all the required parameters and storage fields',
163	                        )
164	                      : t('Source not available')
165	                  }
166	                  hidden={!isQuickCreateDisabled}
167	                >
168	                  <span>
169	                    <Button
170	                      data-test-id="quick-create-vm-btn"
171	                      form={DRAWER_FORM_ID}
172	                      isDisabled={isQuickCreateDisabled}
173	                      isLoading={isQuickCreateLoading}
174	                      onClick={onQuickCreate}
175	                      type="submit"
176	                    >
177	                      {t('Quick create VirtualMachine')}
178	                    </Button>
179	                  </span>
180	                </Tooltip>
181	              </SplitItem>
182	              <SplitItem>
183	                <Button
184	                  data-test-id="customize-vm-btn"
185	                  form={DRAWER_FORM_ID}
186	                  isDisabled={isCustomizeDisabled}
187	                  isLoading={isCustomizeLoading}
188	                  onClick={onCustomize}
189	                  variant={ButtonVariant.secondary}
190	                >
191	                  {t('Customize VirtualMachine')}
192	                </Button>
193	              </SplitItem>
194	              <Button onClick={() => onCancel()} variant={ButtonVariant.link}>
195	                {t('Cancel')}
196	              </Button>
197	            </Split>
198	          </StackItem>
199	        </Stack>
200	      </form>
201	    );
202	  },
203	);

